const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

readline.question('', (number) => {
    number = parseInt(number);
    // Check if the number is even or odd
    if (number % 2 == 0) {
        console.log("Even");
    } else {
        console.log("Odd");
    }
    readline.close();
});
